import React, { useState } from 'react';
import { styles } from '../styles';
import searchIcon from '../search.svg';
import CartDrawer from './CartDrawer';
import UserLogin from './UserLogin';

const formatINR = (amount) =>
  new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 0
  }).format(amount);

// Sample product data (mocked for now)
const products = [
  {
    id: 1,
    name: 'Amul Taaza Toned Milk',
    price: 32,
    originalPrice: 36,
    discount: 44,
    image: 'https://images.unsplash.com/photo-1550583724-b2692b85b150?auto=format&fit=crop&w=600&q=80',
    delivery: '8 MINS',
    volume: '500 ml',
  },
  {
    id: 2,
    name: 'Fresh Bananas',
    price: 45,
    originalPrice: 55,
    discount: 18,
    image: 'https://images.unsplash.com/photo-1574226516831-e1dff420e43e?auto=format&fit=crop&w=600&q=80',
    delivery: '8 MINS',
    volume: '1 dozen',
  },
  {
    id: 3,
    name: 'Aashirvaad Whole Wheat Atta',
    price: 289,
    originalPrice: 320,
    discount: 10,
    image: 'https://images.unsplash.com/photo-1608198093002-ad4e005484ec?auto=format&fit=crop&w=600&q=80',
    delivery: '10 MINS',
    volume: '5 kg',
  },
  {
    id: 4,
    name: 'Farm Fresh Eggs',
    price: 92,
    originalPrice: 110,
    discount: 16,
    image: 'https://images.unsplash.com/photo-1518492104633-130d0cc84637?auto=format&fit=crop&w=600&q=80',
    delivery: '8 MINS',
    volume: '12 pcs',
  },
  {
    id: 5,
    name: 'Tata Tea Gold',
    price: 178,
    originalPrice: 210,
    discount: 15,
    image: 'https://images.unsplash.com/photo-1597318181409-cf64d0b5d8a2?auto=format&fit=crop&w=600&q=80',
    delivery: '9 MINS',
    volume: '500 g',
  },
  {
    id: 6,
    name: 'Tomatoes',
    price: 34,
    originalPrice: 42,
    discount: 19,
    image: 'https://images.unsplash.com/photo-1546094096-0df4bcaaa337?auto=format&fit=crop&w=600&q=80',
    delivery: '7 MINS',
    volume: '1 kg',
  },
];


export default function CustomerView() {
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState("");
  const [cartOpen, setCartOpen] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [isUserLoggedIn, setIsUserLoggedIn] = useState(!!localStorage.getItem('userToken'));

  const addToCart = (product) => {
    setCart((prev) => [...prev, product]);
  };

  // Filter products by search
  const filteredProducts = products.filter((product) =>
    product.name.toLowerCase().includes(search.toLowerCase())
  );

  // Handler for cart checkout button
  const handleCartCheckout = () => {
    if (!isUserLoggedIn) {
      setShowLogin(true);
    } else {
      // Proceed to order management or checkout
      alert('Proceeding to order management (user is logged in)');
    }
  };

  // Handler after successful login
  const handleUserLogin = () => {
    setIsUserLoggedIn(true);
    setShowLogin(false);
  };

  return (
    <>
      <header style={styles.header}>
        <span style={styles.logo}>blinkit</span>
        <span style={styles.location}>
          <span role="img" aria-label="location">📍</span>
          Delivery in 8 minutes
        </span>
        <div style={styles.searchWrap}>
          <input
            type="text"
            placeholder="Search 'bread'"
            value={search}
            onChange={e => setSearch(e.target.value)}
            style={styles.searchInput}
          />
          <img src={searchIcon} alt="search" style={styles.searchIcon} />
        </div>
        <button style={styles.cartBtn} onClick={() => setCartOpen(true)}>
          <span role="img" aria-label="cart">🛒</span>
          <span>{cart.length > 0 ? `${cart.length} item${cart.length > 1 ? 's' : ''}` : 'Cart'}</span>
        </button>
      </header>
      <main style={styles.main}>
        <div style={styles.sectionTitle}>Buy Bath & Beauty Gifts Online</div>
        <div style={styles.productGrid}>
          {filteredProducts.map((product) => (
            <div key={product.id} style={styles.productCard}>
              <img src={product.image} alt={product.name} style={styles.productImg} />
              <div style={styles.productName}>{product.name}</div>
              <div style={styles.productVolume}>{product.volume}</div>
              <div style={styles.priceRow}>
                <span style={styles.price}>{formatINR(product.price)}</span>
                <span style={styles.originalPrice}>{formatINR(product.originalPrice)}</span>
                <span style={styles.discount}>{product.discount}% OFF</span>
              </div>
              <div style={styles.delivery}>{product.delivery}</div>
              <button onClick={() => addToCart(product)} style={styles.addBtn}>ADD</button>
            </div>
          ))}
        </div>
      </main>
      {cartOpen && (
        <CartDrawer cart={cart} onClose={() => setCartOpen(false)} onCheckout={handleCartCheckout} />
      )}
      {showLogin && (
        <UserLogin onLogin={handleUserLogin} />
      )}
    </>
  );
}
